    // 명확한 비식재료는 제외
    const nonFoodItems = ['person', 'hand', 'human', 'bottle', 'package', 'container', 'box', 'bag', 'plate', 'bowl', 'cup', 'glass', 'knife', 'fork', 'spoon', 'table', 'chair', 'wall', 'floor', 'ceiling', 'window', 'door', 'plastic', 'metal', 'wood', 'paper', 'cloth', 'fabric'];
    
